    22→function bureau_it_custom_event_display($event = null) {
    23→    $event = $event ?? tribe_get_event();
    24→    if (!$event) return;
    25→
    26→    $categories = wp_get_post_terms($event->ID, 'tribe_events_cat');
    27→    if (!is_wp_error($categories)) {
    28→        foreach ($categories as $category) {
    29→            if (strtolower($category->slug) === 'edital') {
    30→                // Custom logic here
    31→                break;
    32→            }
    33→        }
    34→    }
    35→}
