    37→add_filter('tec_events_get_time_range_separator', function($separator) {
    38→    return (strpos($separator, '#') !== false) ? ' - ' : $separator;
    39→});
    40→
    41→add_filter('tec_events_get_date_time_separator', function($separator) {
    42→    return (strpos($separator, '#') !== false) ? ' @ ' : $separator;
    43→});
