    45→/**
    46→ * Verifica se um evento é da categoria "edital"
    47→ *
    48→ * @param WP_Post|int $event Objeto do evento ou ID
    49→ * @return bool
    50→ */
    51→function bureau_it_is_edital($event) {
    52→    $event_id = is_object($event) ? $event->ID : $event;
    53→    return has_term('edital', 'tribe_events_cat', $event_id);
    54→}
    55→
    56→/**
    57→ * Filtro para modificar a data exibida dos eventos na lista
    58→ * Funciona para eventos da categoria "edital" em qualquer view/shortcode
    59→ *
    60→ * @since 1.4.2
    61→ */
    62→add_filter('tribe_events_event_schedule_details', 'bureau_it_filter_edital_schedule', 10, 2);
    63→function bureau_it_filter_edital_schedule($schedule, $event_id) {
    64→    if (!bureau_it_is_edital($event_id)) {
    65→        return $schedule;
    66→    }
    67→
    68→    $event = tribe_get_event($event_id);
    69→    if (!$event || !isset($event->dates->end)) {
    70→        return $schedule;
    71→    }
    72→
    73→    $end_date = $event->dates->end;
    74→    $formatted = wp_date('j \d\e F', $end_date->getTimestamp());
    75→
    76→    return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html($formatted) . '</span>';
    77→}
