    79→/**
    80→ * Filtro alternativo para short_schedule_details (usado em widgets)
    81→ *
    82→ * @since 1.4.2
    83→ */
    84→add_filter('tribe_events_event_short_schedule_details', 'bureau_it_filter_edital_short_schedule', 10, 2);
    85→function bureau_it_filter_edital_short_schedule($schedule, $event_id) {
    86→    if (!bureau_it_is_edital($event_id)) {
    87→        return $schedule;
    88→    }
    89→
    90→    $event = tribe_get_event($event_id);
    91→    if (!$event || !isset($event->dates->end)) {
    92→        return $schedule;
    93→    }
    94→
    95→    $end_date = $event->dates->end;
    96→    $formatted = wp_date('j \d\e F', $end_date->getTimestamp());
    97→
    98→    return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html($formatted) . '</span>';
    99→}
   100→
   101→/**
   102→ * Formata a data de um evento para exibição customizada
   103→ *
   104→ * Para editais: "Edital disponível até: X de Mês"
   105→ * Para eventos: Formato padrão com correções de localização
   106→ *
   107→ * @param WP_Post $event Objeto do evento com propriedades do tribe_get_event()
   108→ * @param bool    $add_prefix Adicionar "De " no início para eventos normais
   109→ * @return string HTML formatado da data
   110→ */
   111→function bureau_it_format_event_date($event, $add_prefix = true) {
   112→    if (bureau_it_is_edital($event)) {
   113→        $end_date = $event->dates->end;
   114→        $formatted = wp_date('j \d\e F', $end_date->getTimestamp());
   115→        return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html($formatted) . '</span>';
   116→    }
   117→
   118→    // Eventos normais: aplicar correções de formato
   119→    $date_text = $event->schedule_details->value();
   120→
   121→    // Correções de localização pt-BR
   122→    $date_text = str_replace('Virtual Evento', 'Evento Virtual', $date_text);
   123→    $date_text = str_replace('-3', 'Horário de São Paulo', $date_text);
   124→
   125→    // Corrigir formato da data: "Month DD @ HH:MM" → "DD de Month às HH:MM"
   126→    $date_text = preg_replace_callback(
   127→        '/(\w+)\s(\d+)\s@\s(\d+):(\d+)/i',
   128→        function($matches) {
   129→            return $matches[2] . ' de ' . $matches[1] . ' às ' . $matches[3] . ':' . $matches[4];
   130→        },
   131→        $date_text
   132→    );
   133→
   134→    // Substituir separador de intervalo
   135→    $date_text = str_replace('</span> - <span', '</span> até <span', $date_text);
   136→
   137→    // Adicionar prefixo "De " se solicitado
   138→    if ($add_prefix && strpos($date_text, '<span class="tribe-event-date-start">') !== false) {
   139→        $date_text = 'De ' . $date_text;
   140→    }
   141→
   142→    return $date_text;
   143→}
