   342→/**
   343→ * Alphabet filter support for CCT queries (JetSmartFilters + JetEngine CCT)
   344→ *
   345→ * JetSmartFilters stores the selected letter in final_query['alphabet'],
   346→ * but CCT_Query::_get_items() ignores it. This hook converts the letter
   347→ * to a LIKE condition on item_title so the alphabet filter works with CCT.
   348→ *
   349→ * @since 1.5.1
   350→ */
   351→add_action('jet-engine/query-builder/query/before-get-items', 'bureau_it_cct_alphabet_filter', 10, 2);
   352→function bureau_it_cct_alphabet_filter($query, $cached) {
   353→    if ($cached) {
   354→        return;
   355→    }
   356→
   357→    if ($query->query_type !== 'custom-content-type') {
   358→        return;
   359→    }
   360→
   361→    if (empty($query->final_query['alphabet'])) {
   362→        return;
   363→    }
   364→
   365→    $letter = $query->final_query['alphabet'];
   366→    if (is_array($letter)) {
   367→        $letter = reset($letter);
   368→    }
   369→    $letter = mb_substr(sanitize_text_field($letter), 0, 1);
   370→
   371→    if (empty($letter)) {
   372→        return;
   373→    }
   374→
   375→    if (!isset($query->final_query['args']) || !is_array($query->final_query['args'])) {
   376→        $query->final_query['args'] = array();
   377→    }
   378→
   379→    $query->final_query['args'][] = array(
   380→        'field'    => 'item_title',
   381→        'operator' => 'LIKE',
   382→        'value'    => $letter . '%',
   383→    );
   384→
   385→    unset($query->final_query['alphabet']);
   386→}
