   388→/**
   389→ * ============================================================================
   390→ * SVG SHORTCODE - Externalizar SVGs do HTML
   391→ * ============================================================================
   392→ *
   393→ * Carrega SVGs de arquivos externos no diretorio svg/ do tema filho,
   394→ * eliminando SVGs inline do HTML (economia de ~178KB na home).
   395→ *
   396→ * Uso: [bureau_svg name="logo-br"]
   397→ *      [bureau_svg name="logo-br" class="my-class" id="my-id"]
   398→ *      [bureau_svg name="spiral-2026" class="SVGSpiral2026"]
   399→ *
   400→ * @since 1.5.0
   401→ */
   402→add_shortcode('bureau_svg', 'bureau_it_svg_shortcode');
   403→function bureau_it_svg_shortcode($atts) {
   404→    $atts = shortcode_atts(array(
   405→        'name'  => '',
   406→        'class' => '',
   407→        'id'    => '',
   408→    ), $atts, 'bureau_svg');
   409→
   410→    if (empty($atts['name'])) {
   411→        return '';
   412→    }
   413→
   414→    $file = get_stylesheet_directory() . '/svg/' . sanitize_file_name($atts['name']) . '.svg';
   415→    if (!file_exists($file)) {
   416→        return '';
   417→    }
   418→
   419→    $svg = file_get_contents($file);
   420→    if (empty($svg)) {
   421→        return '';
   422→    }
   423→
   424→    if (!empty($atts['class'])) {
   425→        if (preg_match('/\bclass="[^"]*"/', $svg)) {
   426→            $svg = preg_replace('/\bclass="([^"]*)"/', 'class="$1 ' . esc_attr($atts['class']) . '"', $svg, 1);
   427→        } else {
   428→            $svg = preg_replace('/<svg\b/', '<svg class="' . esc_attr($atts['class']) . '"', $svg, 1);
   429→        }
   430→    }
   431→
   432→    if (!empty($atts['id'])) {
   433→        if (preg_match('/\bid="[^"]*"/', $svg)) {
   434→            $svg = preg_replace('/\bid="[^"]*"/', 'id="' . esc_attr($atts['id']) . '"', $svg, 1);
   435→        } else {
   436→            $svg = preg_replace('/<svg\b/', '<svg id="' . esc_attr($atts['id']) . '"', $svg, 1);
   437→        }
   438→    }
   439→
   440→    return $svg;
   441→}
   442→
   443→
   444→/**
   445→ * Shortcode para logos como <img> com troca de idioma via WPML/CSS
   446→ *
   447→ * Usa <img src="logo.svg"> em vez de SVG inline, permitindo cache do browser
   448→ * e reduzindo ~46KB por logo no HTML renderizado.
   449→ * Troca BR/EN via CSS baseado no atributo lang do <html> (WPML).
   450→ *
   451→ * Uso: [bureau_logo wrapper_class="site-logo"]
   452→ *      [bureau_logo wrapper_class="footer-logo" height="120"]
   453→ *
   454→ * @since 1.5.0
   455→ */
   456→add_shortcode('bureau_logo', 'bureau_it_logo_shortcode');
   457→function bureau_it_logo_shortcode($atts) {
   458→    $atts = shortcode_atts(array(
   459→        'wrapper_class' => 'site-logo',
   460→        'id_br'         => '',
   461→        'id_en'         => '',
   462→        'height'        => '',
   463→    ), $atts, 'bureau_logo');
   464→
   465→    $svg_uri = get_stylesheet_directory_uri() . '/svg/';
   466→    $svg_dir = get_stylesheet_directory() . '/svg/';
   467→
   468→    if (!file_exists($svg_dir . 'logo-br.svg')) {
   469→        return '';
   470→    }
   471→
   472→    $wrapper = esc_attr($atts['wrapper_class']);
   473→    $height_attr = !empty($atts['height']) ? ' height="' . esc_attr($atts['height']) . '"' : '';
   474→    $id_br = !empty($atts['id_br']) ? ' id="' . esc_attr($atts['id_br']) . '"' : '';
   475→    $id_en = !empty($atts['id_en']) ? ' id="' . esc_attr($atts['id_en']) . '"' : '';
   476→
   477→    $output = '<div class="' . $wrapper . '">';
   478→    $output .= '<img class="bureau-logo-br" src="' . esc_url($svg_uri . 'logo-br.svg') . '" alt="Uma Concertação pela Amazônia"' . $id_br . $height_attr . ' />';
   479→    if (file_exists($svg_dir . 'logo-en.svg')) {
   480→        $output .= '<img hidden class="bureau-logo-en" src="' . esc_url($svg_uri . 'logo-en.svg') . '" alt="A Concertation for the Amazon"' . $id_en . $height_attr . ' />';
   481→    }
   482→    $output .= '</div>';
   483→
   484→    return $output;
   485→}
   486→
   487→/**
   488→ * ============================================================================
   489→ * PERFORMANCE: Dequeue CSS/JS desnecessarios na Home
   490→ * ============================================================================
   491→ *
   492→ * Remove assets nao utilizados na homepage para reduzir requests.
   493→ * Nota: CSS do The Events Calendar mantido (sera usado em proxima publicacao).
   494→ *
   495→ * @since 1.5.0
   496→ */
   497→add_action('wp_enqueue_scripts', 'bureau_it_dequeue_homepage_assets', 999);
   498→function bureau_it_dequeue_homepage_assets() {
   499→    if (!is_front_page()) {
   500→        return;
   501→    }
   502→
   503→    // Chosen.js: 3 plugins registram chosen (TEC, GravityForms, JetSearch)
   504→    wp_dequeue_style('tribe-events-chosen-style');
   505→    wp_dequeue_script('tribe-events-chosen-jquery');
   506→    wp_dequeue_style('gform_chosen');
   507→    wp_dequeue_script('gform_chosen');
   508→    wp_dequeue_style('jquery-chosen');
   509→    wp_dequeue_script('jquery-chosen');
   510→
   511→    // Slick.js: Elementor ja tem Swiper nativo
   512→    wp_dequeue_script('jet-slick');
   513→    wp_dequeue_script('jquery-slick');
   514→}
   515→
   516→// Dequeue tambem no wp_print_footer_scripts (JetEngine/JetSearch podem enfileirar tarde)
   517→add_action('wp_print_footer_scripts', 'bureau_it_dequeue_homepage_assets', 1);
   518→
   519→/**
   520→ * Conditional dequeue: jet-elements JS and jet-smart-filters on pages that don't use them
   521→ *
   522→ * Checks _elementor_data for JetElements widgets requiring JS.
   523→ * Economy: ~59KB on pages like 4-amazonias.
   524→ *
   525→ * @since 1.6.0
   526→ */
   527→add_action('wp_enqueue_scripts', 'bureau_it_dequeue_unused_jet_assets', 999);
   528→function bureau_it_dequeue_unused_jet_assets() {
   529→    if (is_admin() || !is_singular()) {
   530→        return;
   531→    }
   532→
   533→    $post_id = get_the_ID();
   534→    if (!$post_id) {
   535→        return;
   536→    }
   537→
   538→    $data = get_post_meta($post_id, '_elementor_data', true);
   539→    if (empty($data)) {
   540→        return;
   541→    }
   542→
   543→    // JetElements widgets that require JS (sliders, carousels, etc.)
   544→    $jet_js_widgets = [
   545→        'jet-slider',
   546→        'jet-carousel',
   547→        'jet-posts',
   548→        'jet-animated-text',
   549→        'jet-testimonials',
   550→        'jet-image-comparison',
   551→        'jet-countdown-timer',
   552→        'jet-accordion',
   553→        'jet-tabs',
   554→        'jet-toggle',
   555→    ];
   556→
   557→    $needs_jet_js = false;
   558→    foreach ($jet_js_widgets as $widget) {
   559→        if (strpos($data, '"widgetType":"' . $widget . '"') !== false) {
   560→            $needs_jet_js = true;
   561→            break;
   562→        }
   563→    }
   564→
   565→    if (!$needs_jet_js) {
   566→        wp_dequeue_script('jet-elements');
   567→        wp_deregister_script('jet-elements');
   568→    }
   569→
   570→    // Dequeue JetSmartFilters if page doesn't use filter widgets
   571→    $filter_widgets = ['jet-smart-filters-', 'jsfb-'];
   572→    $needs_filters  = false;
   573→    foreach ($filter_widgets as $widget) {
   574→        if (strpos($data, $widget) !== false) {
   575→            $needs_filters = true;
   576→            break;
   577→        }
   578→    }
   579→
   580→    if (!$needs_filters) {
   581→        wp_dequeue_script('jet-smart-filters');
   582→        wp_deregister_script('jet-smart-filters');
   583→    } else {
   584→        // Força CSS no <head> via fila normal — compatível com WP Rocket.
   585→        // O mecanismo padrão do JSF imprime CSS mid-body via wp_print_styles(),
   586→        // que o WP Rocket remove ao combinar CSS. Forçar aqui garante que o
   587→        // <link> seja emitido pelo wp_head() antes do cache ser gerado.
   588→        if (function_exists('jet_smart_filters') && wp_style_is('jet-smart-filters', 'registered')) {
   589→            wp_enqueue_style('jet-smart-filters');
   590→            jet_smart_filters()->filters_not_used = false; // evita print mid-body duplicado
   591→        }
   592→    }
   593→}
   594→
   595→/**
   596→ * ============================================================================
   597→ * PERFORMANCE: Lazy loading para imagens
   598→ * ============================================================================
   599→ *
   600→ * Adiciona loading="lazy" para imagens que nao possuem o atributo.
   601→ *
   602→ * @since 1.5.0
   603→ */
   604→add_filter('wp_get_attachment_image_attributes', 'bureau_it_optimize_image_loading', 10, 3);
   605→function bureau_it_optimize_image_loading($attr, $attachment, $size) {
   606→    // banner-home usa slick carousel com infinite clone — lazy loading quebra imagens em slides clonados
   607→    if (get_post_type() === 'banner-home') {
   608→        $attr['loading'] = 'eager';
   609→        return $attr;
   610→    }
   611→    if (!isset($attr['loading'])) {
   612→        $attr['loading'] = 'lazy';
   613→    }
   614→    return $attr;
   615→}
   616→
   617→/**
   618→ * ============================================================================
   619→ * ELEMENTOR PRO BUG FIX: SVG Links
   620→ * ============================================================================
   621→ *
   622→ * Fix para bug do Elementor Pro 3.33.x onde o módulo Off-Canvas falha ao
   623→ * processar links dentro de elementos SVG. O erro ocorre porque links SVG
   624→ * retornam SVGAnimatedString (objeto) ao invés de string para a propriedade
   625→ * .href, e o Elementor tenta chamar .includes() que não existe nesse objeto.
   626→ *
   627→ * Este fix adiciona o método .includes() ao prototype de SVGAnimatedString.
   628→ *
   629→ * @since 1.4.1
   630→ * @see https://github.com/elementor/elementor/issues/XXXXX
   631→ */
   632→add_action('wp_head', 'bureau_it_fix_elementor_svg_links', 1);
   633→function bureau_it_fix_elementor_svg_links() {
   634→    ?>
   635→    <script>
   636→    // Fix: Elementor Pro Off-Canvas + SVG links compatibility
   637→    // SVGAnimatedString doesn't have .includes(), causing TypeError
   638→    if (typeof SVGAnimatedString !== 'undefined' && !SVGAnimatedString.prototype.includes) {
   639→        SVGAnimatedString.prototype.includes = function(searchString) {
   640→            return this.baseVal.includes(searchString);
   641→        };
   642→    }
   643→    </script>
   644→    <?php
   645→}
   646→
   647→/**
   648→ * ============================================================================
   649→ * MULTISITE: Shared uploads symlinks (subsite blog_id=2)
   650→ * ============================================================================
   651→ *
   652→ * Subsite /cultura/ generates upload URLs with /sites/2/YYYY/MM/ but actual
   653→ * files are in /wp-content/uploads/YYYY/MM/ (shared from single-site era).
   654→ * Creates symlinks sites/2/YYYY -> ../../YYYY on first request if missing.
   655→ *
   656→ * @since 1.6.1
   657→ */
   658→add_action('init', 'bureau_it_ensure_shared_upload_symlinks', 1);
   659→function bureau_it_ensure_shared_upload_symlinks() {
   660→    if (!is_multisite() || get_current_blog_id() !== 2) {
   661→        return;
   662→    }
   663→
   664→    $upload_dir = ABSPATH . 'wp-content/uploads';
   665→    $sites_dir  = "$upload_dir/sites/2";
   666→
   667→    if (!is_dir($sites_dir)) {
   668→        @mkdir($sites_dir, 0755, true);
   669→    }
   670→
   671→    foreach (glob("$upload_dir/20[0-9][0-9]", GLOB_ONLYDIR) as $year_dir) {
   672→        $year = basename($year_dir);
   673→        $link = "$sites_dir/$year";
   674→        if (!file_exists($link)) {
   675→            @symlink("../../$year", $link);
   676→        }
   677→    }
   678→}
