function bureau_it_is_edital($event) {
    $event_id = is_object($event) ? $event->ID : $event;

    // TEC Custom Tables V1: provisional occurrence IDs are not real post IDs.
    // Resolve to the actual post_id before checking terms.
    if ( function_exists( 'tec_get_post_id_from_occurrence_id' ) ) {
        $real_id = tec_get_post_id_from_occurrence_id( $event_id );
        if ( $real_id ) {
            $event_id = $real_id;
        }
    } elseif (
        is_object( $event )
        && isset( $event->_tec_occurrences )
        && ! empty( $event->_tec_occurrences )
    ) {
        // $event->_tec_occurrences may hold the real post_id
        $first = reset( $event->_tec_occurrences );
        if ( isset( $first->post_id ) ) {
            $event_id = $first->post_id;
        }
    } else {
        // Fallback: query wp_tec_occurrences directly
        global $wpdb;
        $table = $wpdb->prefix . 'tec_occurrences';
        if ( $wpdb->get_var( "SHOW TABLES LIKE '$table'" ) === $table ) {
            $real_id = $wpdb->get_var( $wpdb->prepare(
                "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
                $event_id
            ) );
            if ( ! $real_id ) {
                // Try treating the ID as composite: the real occurrence_id may be the last digits
                // TEC provisonal IDs: subtract 1e7 offset used internally
                $candidate = absint( $event_id ) - 10000000;
                if ( $candidate > 0 ) {
                    $real_id = $wpdb->get_var( $wpdb->prepare(
                        "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
                        $candidate
                    ) );
                }
            }
            if ( $real_id ) {
                $event_id = $real_id;
            }
        }
    }

    return has_term( 'edital', 'tribe_events_cat', $event_id );
}

