    28→function bureau_it_page_uses_tec() {
    29→    // TEC event queries: /eventos-calendario/, single events, etc.
    30→    if ( function_exists( 'tribe_is_event_query' ) && tribe_is_event_query() ) {
    31→        return true;
    32→    }
    33→
    34→    // Páginas singulares: verificar shortcode e widget Elementor
    35→    if ( is_singular() ) {
    36→        $post = get_post();
    37→        if ( ! $post ) {
    38→            return false;
