    43→            return true;
    44→        }
    45→
    46→        // Widget Elementor nativo do TEC
    47→        $elementor_data = get_post_meta( $post->ID, '_elementor_data', true );
    48→        if ( $elementor_data && str_contains( $elementor_data, 'tec_elementor_widget' ) ) {
    49→            return true;
