    72→add_filter('tribe_events_assets_should_enqueue_frontend', 'bureau_it_tec_assets_should_enqueue_frontend');
    73→function bureau_it_tec_assets_should_enqueue_frontend( $should_enqueue ) {
    74→    // Se o TEC já decidiu carregar (event query, shortcode clássico), respeitar
    75→    if ( $should_enqueue ) {
