   160→/**
   161→ * Verifica se um evento é da categoria "edital"
   162→ *
   163→ * @param WP_Post|int $event Objeto do evento ou ID
   164→ * @return bool
   165→ */
   166→function bureau_it_is_edital($event) {
   167→    $event_id = is_object($event) ? $event->ID : $event;
   168→
   169→    // TEC Custom Tables V1: provisional occurrence IDs are not real post IDs.
   170→    // Resolve to the actual post_id before checking terms.
   171→    if ( function_exists( 'tec_get_post_id_from_occurrence_id' ) ) {
   172→        $real_id = tec_get_post_id_from_occurrence_id( $event_id );
   173→        if ( $real_id ) {
   174→            $event_id = $real_id;
   175→        }
   176→    } elseif (
   177→        is_object( $event )
   178→        && isset( $event->_tec_occurrences )
   179→        && ! empty( $event->_tec_occurrences )
   180→    ) {
   181→        // $event->_tec_occurrences may hold the real post_id
   182→        $first = reset( $event->_tec_occurrences );
   183→        if ( isset( $first->post_id ) ) {
   184→            $event_id = $first->post_id;
   185→        }
   186→    } else {
   187→        // Fallback: query wp_tec_occurrences directly
   188→        global $wpdb;
   189→        $table = $wpdb->prefix . 'tec_occurrences';
   190→        if ( $wpdb->get_var( "SHOW TABLES LIKE '$table'" ) === $table ) {
   191→            $real_id = $wpdb->get_var( $wpdb->prepare(
   192→                "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
   193→                $event_id
   194→            ) );
   195→            if ( ! $real_id ) {
   196→                // Try treating the ID as composite: the real occurrence_id may be the last digits
   197→                // TEC provisonal IDs: subtract 1e7 offset used internally
   198→                $candidate = absint( $event_id ) - 10000000;
   199→                if ( $candidate > 0 ) {
   200→                    $real_id = $wpdb->get_var( $wpdb->prepare(
   201→                        "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
   202→                        $candidate
   203→                    ) );
   204→                }
   205→            }
   206→            if ( $real_id ) {
   207→                $event_id = $real_id;
   208→            }
   209→        }
   210→    }
   211→
   212→    return has_term( 'edital', 'tribe_events_cat', $event_id );
   213→}
