    39→/**
    40→ * Modifica o HTML do template de data para eventos da categoria "edital"
    41→ *
    42→ * Intercepta a renderização do template de data e substitui o conteúdo
    43→ * para mostrar "Edital disponível até: [data]" em vez do formato padrão.
    44→ */
    45→add_filter('tribe_template_html:events/v2/list/event/date', 'bureau_it_tec_filter_edital_date_html', 10, 4);
    46→add_filter('tribe_template_html:events/v2/widgets/widget-events-list/event/date', 'bureau_it_tec_filter_edital_date_html', 10, 4);
    47→function bureau_it_tec_filter_edital_date_html($html, $file, $name, $template) {
    48→    // Obter o evento do contexto do template
    49→    $context = $template->get_values();
    50→    $event = isset($context['event']) ? $context['event'] : null;
    51→
    52→    if (!$event) {
    53→        return $html;
    54→    }
    55→
    56→    // Verificar se é um edital
    57→    if (!has_term('edital', 'tribe_events_cat', $event->ID)) {
    58→        return $html;
    59→    }
    60→
    61→    // Obter a data de término do evento
    62→    $event_obj = tribe_get_event($event->ID);
    63→    if (!$event_obj || !isset($event_obj->dates->end)) {
    64→        return $html;
    65→    }
    66→
    67→    // Formatar a data
    68→    $end_date = $event_obj->dates->end;
    69→    $formatted_date = wp_date('j \d\e F', $end_date->getTimestamp());
    70→
    71→    // Substituir o conteúdo do elemento time mantendo a estrutura HTML
    72→    $new_date_html = '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html($formatted_date) . '</span>';
    73→
    74→    // Usar regex para substituir o conteúdo do elemento time
    75→    $html = preg_replace(
    76→        '/(<time[^>]*>).*?(<\/time>)/s',
    77→        '$1' . $new_date_html . '$2',
    78→        $html
    79→    );
    80→
    81→    return $html;
    82→}
