    90→function bureau_it_tec_modify_edital_event_vars($template_vars, $view) {
    91→    if (!isset($template_vars['events']) || !is_array($template_vars['events'])) {
    92→        return $template_vars;
    93→    }
    94→
    95→    foreach ($template_vars['events'] as $key => $event) {
    96→        if (!is_object($event) || !isset($event->ID)) {
    97→            continue;
    98→        }
    99→
   100→        // Verificar se é edital
   101→        if (!has_term('edital', 'tribe_events_cat', $event->ID)) {
   102→            continue;
   103→        }
   104→
   105→        // Marcar o evento como edital para uso nos templates
   106→        $template_vars['events'][$key]->is_edital = true;
   107→
   108→        // Se o evento tem datas, adicionar a data formatada
   109→        if (isset($event->dates->end)) {
