   260→/**
   261→ * Formata a data de um evento para exibição customizada
   262→ *
   263→ * Para editais: "Edital disponível até: X de Mês"
   264→ * Para eventos: Formato padrão com correções de localização
   265→ *
   266→ * @param WP_Post $event Objeto do evento com propriedades do tribe_get_event()
   267→ * @param bool    $add_prefix Adicionar "De " no início para eventos normais
   268→ * @return string HTML formatado da data
   269→ */
   270→function bureau_it_format_event_date($event, $add_prefix = true) {
   271→    if (bureau_it_is_edital($event)) {
   272→        $end_date = $event->dates->end;
   273→        $formatted = wp_date('j \d\e F', $end_date->getTimestamp());
   274→        return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html($formatted) . '</span>';
   275→    }
   276→
   277→    // Eventos normais: aplicar correções de formato
   278→    $date_text = $event->schedule_details->value();
   279→
   280→    // Correções de localização pt-BR
   281→    $date_text = str_replace('Virtual Evento', 'Evento Virtual', $date_text);
   282→    $date_text = str_replace('-3', 'Horário de São Paulo', $date_text);
   283→
   284→    // Corrigir formato da data: "Month DD @ HH:MM" → "DD de Month às HH:MM"
   285→    $date_text = preg_replace_callback(
   286→        '/(\w+)\s(\d+)\s@\s(\d+):(\d+)/i',
   287→        function($matches) {
   288→            return $matches[2] . ' de ' . $matches[1] . ' às ' . $matches[3] . ':' . $matches[4];
   289→        },
   290→        $date_text
   291→    );
   292→
   293→    // Substituir separador de intervalo
   294→    $date_text = str_replace('</span> - <span', '</span> até <span', $date_text);
   295→
   296→    // Adicionar prefixo "De " se solicitado
   297→    if ($add_prefix && strpos($date_text, '<span class="tribe-event-date-start">') !== false) {
   298→        $date_text = 'De ' . $date_text;
   299→    }
   300→
   301→    return $date_text;
   302→}
