   289→/**
   290→ * Formata a data de um evento para exibição customizada
   291→ *
   292→ * Para editais: "Edital disponível até: X de Mês"
   293→ * Para eventos: Formato padrão com correções de localização
   294→ *
   295→ * @since 1.0.0
   296→ * @param WP_Post $event      Objeto do evento com propriedades do tribe_get_event()
   297→ * @param bool    $add_prefix Adicionar "De " no início para eventos normais
   298→ * @return string HTML formatado da data
   299→ */
   300→function bureau_it_format_event_date( $event, $add_prefix = true ) {
   301→    if ( bureau_it_is_edital( $event ) ) {
   302→        if ( ! isset( $event->dates->end ) ) {
   303→            return '';
   304→        }
   305→        $formatted = wp_date( 'j \d\e F', $event->dates->end->getTimestamp() );
   306→
   307→        return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html( $formatted ) . '</span>';
   308→    }
   309→
   310→    // Eventos normais: aplicar correções de formato
   311→    $date_text = wp_kses_post( $event->schedule_details->value() );
   312→
   313→    // Correções de localização pt-BR
   314→    $date_text = str_replace( 'Virtual Evento', 'Evento Virtual', $date_text );
   315→    $date_text = preg_replace( '/\(UTC-3\)/i', 'Horário de São Paulo', $date_text );
   316→
   317→    // Corrigir formato da data: "Month DD @ HH:MM" → "DD de Month às HH:MM"
   318→    $date_text = preg_replace_callback(
   319→        '/(\w+)\s(\d+)\s@\s(\d+):(\d+)/i',
   320→        function ( $matches ) {
   321→            return $matches[2] . ' de ' . $matches[1] . ' às ' . $matches[3] . ':' . $matches[4];
   322→        },
   323→        $date_text
   324→    );
   325→
   326→    // Substituir separador de intervalo
   327→    $date_text = str_replace( '</span> - <span', '</span> até <span', $date_text );
   328→
   329→    // Adicionar prefixo "De " se solicitado
   330→    if ( $add_prefix && strpos( $date_text, '<span class="tribe-event-date-start">' ) !== false ) {
   331→        $date_text = 'De ' . $date_text;
   332→    }
   333→
   334→    return $date_text;
   335→}
