   370→/**
   371→ * Alphabet filter support for CCT queries (JetSmartFilters + JetEngine CCT)
   372→ *
   373→ * JetSmartFilters stores the selected letter in final_query['alphabet'],
   374→ * but CCT_Query::_get_items() ignores it. This hook converts the letter
   375→ * to a LIKE condition on item_title so the alphabet filter works with CCT.
   376→ *
   377→ * @since 1.5.1
   378→ */
   379→add_action('jet-engine/query-builder/query/before-get-items', 'bureau_it_cct_alphabet_filter', 10, 2);
   380→function bureau_it_cct_alphabet_filter($query, $cached) {
   381→    if ($cached) {
   382→        return;
   383→    }
   384→
   385→    if ($query->query_type !== 'custom-content-type') {
   386→        return;
   387→    }
   388→
   389→    if (empty($query->final_query['alphabet'])) {
   390→        return;
   391→    }
   392→
   393→    $letter = $query->final_query['alphabet'];
   394→    if (is_array($letter)) {
   395→        $letter = reset($letter);
   396→    }
   397→    $letter = mb_substr(sanitize_text_field($letter), 0, 1);
   398→
   399→    if (empty($letter)) {
   400→        return;
   401→    }
   402→
   403→    if (!isset($query->final_query['args']) || !is_array($query->final_query['args'])) {
   404→        $query->final_query['args'] = array();
   405→    }
   406→
   407→    $query->final_query['args'][] = array(
   408→        'field'    => 'item_title',
   409→        'operator' => 'LIKE',
   410→        'value'    => $letter . '%',
   411→    );
   412→
   413→    unset($query->final_query['alphabet']);
   414→}
