   416→/**
   417→ * ============================================================================
   418→ * SVG SHORTCODE - Externalizar SVGs do HTML
   419→ * ============================================================================
   420→ *
   421→ * Carrega SVGs de arquivos externos no diretorio svg/ do tema filho,
   422→ * eliminando SVGs inline do HTML (economia de ~178KB na home).
   423→ *
   424→ * Uso: [bureau_svg name="logo-br"]
   425→ *      [bureau_svg name="logo-br" class="my-class" id="my-id"]
   426→ *      [bureau_svg name="spiral-2026" class="SVGSpiral2026"]
   427→ *
   428→ * @since 1.5.0
   429→ */
   430→add_shortcode('bureau_svg', 'bureau_it_svg_shortcode');
   431→function bureau_it_svg_shortcode($atts) {
   432→    $atts = shortcode_atts(array(
   433→        'name'  => '',
   434→        'class' => '',
   435→        'id'    => '',
   436→    ), $atts, 'bureau_svg');
   437→
   438→    if (empty($atts['name'])) {
   439→        return '';
   440→    }
   441→
   442→    $file = get_stylesheet_directory() . '/svg/' . sanitize_file_name($atts['name']) . '.svg';
   443→    if (!file_exists($file)) {
   444→        return '';
   445→    }
   446→
   447→    $svg = file_get_contents($file);
   448→    if (empty($svg)) {
   449→        return '';
   450→    }
   451→
   452→    if (!empty($atts['class'])) {
   453→        if (preg_match('/\bclass="[^"]*"/', $svg)) {
   454→            $svg = preg_replace('/\bclass="([^"]*)"/', 'class="$1 ' . esc_attr($atts['class']) . '"', $svg, 1);
   455→        } else {
   456→            $svg = preg_replace('/<svg\b/', '<svg class="' . esc_attr($atts['class']) . '"', $svg, 1);
   457→        }
   458→    }
   459→
   460→    if (!empty($atts['id'])) {
   461→        if (preg_match('/\bid="[^"]*"/', $svg)) {
   462→            $svg = preg_replace('/\bid="[^"]*"/', 'id="' . esc_attr($atts['id']) . '"', $svg, 1);
   463→        } else {
   464→            $svg = preg_replace('/<svg\b/', '<svg id="' . esc_attr($atts['id']) . '"', $svg, 1);
   465→        }
   466→    }
   467→
   468→    return $svg;
   469→}
