   472→/**
   473→ * Shortcode para logos como <img> com troca de idioma via WPML/CSS
   474→ *
   475→ * Usa <img src="logo.svg"> em vez de SVG inline, permitindo cache do browser
   476→ * e reduzindo ~46KB por logo no HTML renderizado.
   477→ * Troca BR/EN via CSS baseado no atributo lang do <html> (WPML).
   478→ *
   479→ * Uso: [bureau_logo wrapper_class="site-logo"]
   480→ *      [bureau_logo wrapper_class="footer-logo" height="120"]
   481→ *
   482→ * @since 1.5.0
   483→ */
   484→add_shortcode('bureau_logo', 'bureau_it_logo_shortcode');
   485→function bureau_it_logo_shortcode($atts) {
   486→    $atts = shortcode_atts(array(
   487→        'wrapper_class' => 'site-logo',
   488→        'id_br'         => '',
   489→        'id_en'         => '',
   490→        'height'        => '',
   491→    ), $atts, 'bureau_logo');
   492→
   493→    $svg_uri = get_stylesheet_directory_uri() . '/svg/';
   494→    $svg_dir = get_stylesheet_directory() . '/svg/';
   495→
   496→    if (!file_exists($svg_dir . 'logo-br.svg')) {
   497→        return '';
   498→    }
   499→
   500→    $wrapper = esc_attr($atts['wrapper_class']);
   501→    $height_attr = !empty($atts['height']) ? ' height="' . esc_attr($atts['height']) . '"' : '';
   502→    $id_br = !empty($atts['id_br']) ? ' id="' . esc_attr($atts['id_br']) . '"' : '';
   503→    $id_en = !empty($atts['id_en']) ? ' id="' . esc_attr($atts['id_en']) . '"' : '';
   504→
   505→    $output = '<div class="' . $wrapper . '">';
   506→    $output .= '<img class="bureau-logo-br" src="' . esc_url($svg_uri . 'logo-br.svg') . '" alt="Uma Concertação pela Amazônia"' . $id_br . $height_attr . ' />';
   507→    if (file_exists($svg_dir . 'logo-en.svg')) {
   508→        $output .= '<img hidden class="bureau-logo-en" src="' . esc_url($svg_uri . 'logo-en.svg') . '" alt="A Concertation for the Amazon"' . $id_en . $height_attr . ' />';
   509→    }
   510→    $output .= '</div>';
   511→
   512→    return $output;
   513→}
