   547→/**
   548→ * Conditional dequeue: jet-elements JS and jet-smart-filters on pages that don't use them
   549→ *
   550→ * Checks _elementor_data for JetElements widgets requiring JS.
   551→ * Economy: ~59KB on pages like 4-amazonias.
   552→ *
   553→ * @since 1.6.0
   554→ */
   555→add_action('wp_enqueue_scripts', 'bureau_it_dequeue_unused_jet_assets', 999);
   556→function bureau_it_dequeue_unused_jet_assets() {
   557→    if (is_admin() || !is_singular()) {
   558→        return;
   559→    }
   560→
   561→    $post_id = get_the_ID();
   562→    if (!$post_id) {
   563→        return;
   564→    }
   565→
   566→    $data = get_post_meta($post_id, '_elementor_data', true);
   567→    if (empty($data)) {
   568→        return;
   569→    }
   570→
   571→    // JetElements widgets that require JS (sliders, carousels, etc.)
   572→    $jet_js_widgets = [
   573→        'jet-slider',
   574→        'jet-carousel',
   575→        'jet-posts',
   576→        'jet-animated-text',
   577→        'jet-testimonials',
   578→        'jet-image-comparison',
   579→        'jet-countdown-timer',
   580→        'jet-accordion',
   581→        'jet-tabs',
   582→        'jet-toggle',
   583→    ];
   584→
   585→    $needs_jet_js = false;
   586→    foreach ($jet_js_widgets as $widget) {
   587→        if (strpos($data, '"widgetType":"' . $widget . '"') !== false) {
   588→            $needs_jet_js = true;
   589→            break;
   590→        }
   591→    }
   592→
   593→    if (!$needs_jet_js) {
   594→        wp_dequeue_script('jet-elements');
   595→        wp_deregister_script('jet-elements');
   596→    }
   597→
   598→    // Dequeue JetSmartFilters if page doesn't use filter widgets
   599→    $filter_widgets = ['jet-smart-filters-', 'jsfb-'];
   600→    $needs_filters  = false;
   601→    foreach ($filter_widgets as $widget) {
   602→        if (strpos($data, $widget) !== false) {
   603→            $needs_filters = true;
   604→            break;
   605→        }
   606→    }
   607→
   608→    if (!$needs_filters) {
   609→        wp_dequeue_script('jet-smart-filters');
   610→        wp_deregister_script('jet-smart-filters');
   611→    } else {
   612→        // Força CSS no <head> via fila normal — compatível com WP Rocket.
   613→        // O mecanismo padrão do JSF imprime CSS mid-body via wp_print_styles(),
   614→        // que o WP Rocket remove ao combinar CSS. Forçar aqui garante que o
   615→        // <link> seja emitido pelo wp_head() antes do cache ser gerado.
   616→        if (function_exists('jet_smart_filters') && wp_style_is('jet-smart-filters', 'registered')) {
   617→            wp_enqueue_style('jet-smart-filters');
   618→            jet_smart_filters()->filters_not_used = false; // evita print mid-body duplicado
   619→        }
   620→    }
   621→}
