   708→/**
   709→ * Fix LCP /cultura/: remove loading="lazy" da imagem hero via output buffer
   710→ *
   711→ * O Elementor injeta loading="lazy" diretamente em image-size.php, contornando
   712→ * o filtro wp_get_attachment_image_attributes. O output buffer é o único mecanismo
   713→ * confiável para alterar o atributo no HTML final.
   714→ *
   715→ * Aplica apenas no blog 2 (/cultura/). blog_id=2 é fixo na criação do subsite —
   716→ * se o banco for reimportado em novo ambiente, verificar que /cultura/ ainda é blog 2.
   717→ *
   718→ * LIMITAÇÃO CONHECIDA: o match usa o nome de arquivo 'Sapopema'. Se a imagem hero
   719→ * for substituída no Elementor por outra com nome diferente, o fix para de funcionar
   720→ * silenciosamente. Alternativa mais robusta: usar Custom Attributes do Elementor Pro
   721→ * (Advanced > Custom Attributes: fetchpriority|high, loading|eager) diretamente no widget.
   722→ *
   723→ * @since 2.1.0
   724→ * @requires PHP 8.0+
   725→ */
   726→add_action('wp', 'bureau_it_cultura_lcp_ob_start');
   727→function bureau_it_cultura_lcp_ob_start() {
   728→    if ( ! is_multisite() || get_current_blog_id() !== 2 ) {
   729→        return;
   730→    }
   731→    ob_start( 'bureau_it_cultura_lcp_ob_callback' );
