   734→function bureau_it_cultura_lcp_ob_callback( $html ) {
   735→    // Early-return para evitar regex em strings vazias ou sem imagens
   736→    if ( empty( $html ) || ! str_contains( $html, 'Sapopema' ) ) {
   737→        return $html;
   738→    }
   739→    return preg_replace(
   740→        '/(<img\s[^>]*Sapopema[^>]*)\sloading="lazy"([^>]*>)/i',
   741→        '$1 loading="eager" fetchpriority="high"$2',
   742→        $html,
   743→        1 // apenas a primeira ocorrência
   744→    );
   745→}
