   143→/**
   144→ * Resolve um occurrence ID do TEC Custom Tables V1 para o post_id real.
   145→ *
   146→ * O TEC V1 usa IDs provisórios (ex: 10001315) nas templates em vez dos post IDs
   147→ * reais (ex: 89737). O offset interno é 10.000.000 + occurrence_id.
   148→ *
   149→ * @since 2.2.0
   150→ * @param int $event_id ID que pode ser provisório ou real
   151→ * @return int ID real do post (ou o $event_id original se não for possível resolver)
   152→ */
   153→function bureau_it_tec_resolve_post_id( $event_id ) {
   154→    $event_id = (int) $event_id;
   155→
   156→    if ( $event_id <= 0 ) {
   157→        return $event_id;
   158→    }
   159→
   160→    // Verificar cache antes de qualquer consulta
   161→    $cache_key = 'bureau_it_tec_post_id_' . $event_id;
   162→    $cached = wp_cache_get( $cache_key, 'bureau_it_tec' );
   163→    if ( false !== $cached ) {
   164→        return (int) $cached;
   165→    }
   166→
   167→    $resolved = $event_id;
   168→
   169→    if ( function_exists( 'tec_get_post_id_from_occurrence_id' ) ) {
   170→        // TEC API oficial (se disponível)
   171→        $real = tec_get_post_id_from_occurrence_id( $event_id );
   172→        if ( $real ) {
   173→            $resolved = (int) $real;
   174→        }
   175→    } else {
   176→        // Fallback: consulta direta em wp_tec_occurrences
   177→        global $wpdb;
   178→        $table = $wpdb->prefix . 'tec_occurrences';
   179→
   180→        // Verificar existência da tabela via information_schema (SQL-safe)
   181→        $table_exists = (bool) $wpdb->get_var( $wpdb->prepare(
   182→            "SELECT 1 FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = %s LIMIT 1",
   183→            $table
   184→        ) );
   185→
   186→        if ( $table_exists ) {
   187→            // Tentar direto pelo occurrence_id
   188→            $real = (int) $wpdb->get_var( $wpdb->prepare(
   189→                "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
   190→                $event_id
   191→            ) );
   192→
   193→            if ( ! $real ) {
   194→                // TEC provisional IDs: offset interno de 10.000.000 + occurrence_id
   195→                // Ex: 10001315 - 10000000 = 1315 (occurrence_id real)
   196→                $candidate = $event_id - 10000000;
   197→                if ( $candidate > 0 ) {
   198→                    $real = (int) $wpdb->get_var( $wpdb->prepare(
   199→                        "SELECT post_id FROM {$table} WHERE occurrence_id = %d LIMIT 1",
   200→                        $candidate
   201→                    ) );
   202→                }
   203→            }
   204→
   205→            if ( $real > 0 ) {
   206→                $resolved = $real;
   207→            }
   208→        }
   209→    }
   210→
   211→    wp_cache_set( $cache_key, $resolved, 'bureau_it_tec', 3600 );
   212→
   213→    return $resolved;
   214→}
