   216→/**
   217→ * Verifica se um evento é da categoria "edital"
   218→ *
   219→ * Suporta IDs provisórios do TEC Custom Tables V1, onde $event->ID pode ser
   220→ * um occurrence ID composto (ex: 10001315) em vez do post_id real (ex: 89737).
   221→ *
   222→ * @since 1.0.0
   223→ * @param WP_Post|int $event Objeto do evento ou ID (real ou provisório)
   224→ * @return bool
   225→ */
   226→function bureau_it_is_edital( $event ) {
   227→    $event_id = is_object( $event ) ? (int) $event->ID : (int) $event;
   228→
   229→    if ( $event_id <= 0 ) {
   230→        return false;
   231→    }
   232→
   233→    $event_id = bureau_it_tec_resolve_post_id( $event_id );
   234→
   235→    return has_term( 'edital', 'tribe_events_cat', $event_id );
   236→}
