   238→/**
   239→ * Filtro para modificar a data exibida dos eventos na lista.
   240→ * Usado em views legadas / shortcodes V1.
   241→ *
   242→ * Para V2 (list view, widget), o template override date.php já aplica a lógica.
   243→ * Este filtro mantém compatibilidade com shortcodes antigos e V1.
   244→ *
   245→ * @since 1.4.2
   246→ */
   247→add_filter('tribe_events_event_schedule_details', 'bureau_it_filter_edital_schedule', 10, 2);
   248→function bureau_it_filter_edital_schedule( $schedule, $event_id ) {
   249→    if ( ! bureau_it_is_edital( $event_id ) ) {
   250→        return $schedule;
   251→    }
   252→
   253→    // Usar ID resolvido para buscar o evento
   254→    $real_id = bureau_it_tec_resolve_post_id( (int) $event_id );
   255→    $event   = tribe_get_event( $real_id );
   256→
   257→    if ( ! $event || ! isset( $event->dates->end ) ) {
   258→        return $schedule;
   259→    }
   260→
   261→    $formatted = wp_date( 'j \d\e F', $event->dates->end->getTimestamp() );
   262→
   263→    return '<span class="tribe-event-edital-date">Edital disponível até: ' . esc_html( $formatted ) . '</span>';
   264→}
